    ".goal-popover{position:fixed;inset:0;display:flex;align-items:center;justify-content:center;padding:24px;z-index:30;background:rgba(31,26,20,.14);backdrop-filter:blur(3px)}.goal-popover.is-hidden{display:none}.goal-popover-card{width:min(860px,calc(100vw - 48px));max-height:calc(100vh - 48px);overflow:auto;display:flex;flex-direction:column;gap:14px;padding:22px;border:1px solid rgba(31,26,20,.12);border-radius:22px;background:rgba(255,255,255,.98);box-shadow:0 18px 36px rgba(31,26,20,.16);transform-origin:center;animation:goal-popover-rise .16s ease}.goal-editor-copy h3{margin:0 0 6px;font-size:22px}.goal-editor-copy p{margin:0;color:var(--muted);line-height:1.5}.goal-popover textarea{width:100%;min-height:220px;resize:vertical;border:1px solid var(--line);border-radius:16px;background:var(--card);padding:14px 16px}.goal-editor-actions{display:flex;justify-content:space-between;gap:10px;align-items:center;flex-wrap:wrap}.goal-editor-action-group{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.goal-editor-status{min-height:18px;font-size:12px;color:var(--muted);line-height:1.4}.provider-control{display:flex;flex-direction:column;gap:8px;padding:12px 14px;border:1px solid rgba(31,26,20,.12);border-radius:16px;background:rgba(255,255,255,.68)}.provider-control-label{font-size:12px;color:var(--muted);letter-spacing:.08em;text-transform:uppercase}.provider-select{width:100%;border:1px solid var(--line);border-radius:12px;background:var(--card);padding:10px 12px}.provider-meta{font-size:12px;color:var(--muted);line-height:1.4}"
