    ".toggle{position:relative;display:flex;align-items:center;gap:10px;padding:10px 12px;border:1px solid var(--line);border-radius:16px;background:rgba(255,255,255,.68)}.toggle input{width:auto}.toggle-copy{font-size:13px;font-weight:600}.toggle-tip{position:absolute;right:0;bottom:calc(100% + 10px);width:240px;padding:10px 12px;border:1px solid rgba(31,26,20,.16);border-radius:12px;background:rgba(31,26,20,.94);color:#f7f3ea;font-size:12px;line-height:1.4;box-shadow:0 10px 24px rgba(31,26,20,.18);opacity:0;pointer-events:none;transform:translateY(4px);transition:opacity .16s ease,transform .16s ease}.toggle:hover .toggle-tip,.toggle:focus-within .toggle-tip{opacity:1;transform:translateY(0)}.is-hidden{display:none!important}"
    "@keyframes goal-popover-rise{from{opacity:0;transform:translateY(-6px) scale(.99)}to{opacity:1;transform:translateY(0) scale(1)}}"
    ".agent-welcome-section{display:flex;flex-direction:column;gap:8px;padding:12px 14px;border:1px solid rgba(31,26,20,.12);border-radius:16px;background:rgba(255,255,255,.68)}.welcomed-agents-list{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:6px}.welcomed-agents-empty{font-size:12px;color:var(--muted);font-style:italic}.welcomed-agent-item{display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:10px;border:1px solid rgba(31,26,20,.08);background:rgba(255,255,255,.9);font-size:12px}.welcomed-agent-id{font-weight:700;color:var(--text)}.welcomed-agent-provider{padding:2px 6px;border-radius:999px;background:rgba(31,26,20,.08);color:var(--muted);font-size:11px;text-transform:uppercase;letter-spacing:.04em}.welcomed-agent-turn{color:var(--muted);font-size:11px;margin-left:auto}.agent-welcome-form{display:flex;gap:8px;align-items:center}"
    ".goal-board-loading{position:absolute;top:18px;right:18px;z-index:36;display:flex;align-items:center;gap:8px;padding:9px 12px;border:1px solid rgba(31,26,20,.12);border-radius:999px;background:rgba(255,253,248,.94);box-shadow:0 10px 24px rgba(31,26,20,.12);font-size:12px;color:var(--muted);font-style:italic;pointer-events:none}.goal-board-loading::before{content:'';display:inline-block;width:10px;height:10px;border:2px solid rgba(31,26,20,.15);border-top-color:var(--muted);border-radius:50%;animation:ov-spin .7s linear infinite;flex-shrink:0}@keyframes ov-spin{to{transform:rotate(360deg)}}.goal-board-grid.is-loading{opacity:.55;pointer-events:none;transition:opacity .15s}"
