    "@media (max-width: 1400px){.goal-board-grid{grid-template-columns:repeat(2,minmax(0,1fr))}}"
    "@media (max-width: 900px){.app{grid-template-columns:1fr}.sidebar{border-right:none;border-bottom:1px solid var(--line);height:auto;position:static}.sidebar-middle{flex:none}.main{height:auto;grid-template-rows:auto auto minmax(480px,1fr)}.main-pane{padding:16px 0 16px 16px}.main-pane.is-map-open{padding:0}.pane-view{border-radius:24px 0 0 24px}.goal-board-grid{grid-template-columns:minmax(0,1fr)}.goal-board-create{grid-template-columns:minmax(0,1fr)}.goal-board-create .toolbar-button{width:100%}.goal-session-card{min-height:150px;padding:16px 48px 16px}.goal-popover{padding:16px}.goal-popover-card{width:min(860px,calc(100vw - 32px));max-height:calc(100vh - 32px)}.composer{flex-direction:column}.composer-actions{width:100%}.entry{grid-template-columns:minmax(0,1fr)}.entry-out .bubble,.entry-in .bubble,.entry-event .bubble,.entry-agent .bubble,.entry-goal-manager .bubble,.entry-turn-cluster .bubble,.entry-goal-cluster .bubble,.entry-system-cluster .bubble,.entry-user-cluster .bubble{grid-column:1;justify-self:stretch}.bubble{max-width:100%}}"
    "</style></head><body>"
    "<div class='app'>"
    "<aside class='sidebar'>"
    "<section class='sidebar-top'>"
    "<div class='sidebar-topbar'><div class='sidebar-label'>Workspace Header</div>"
    f"<h1 class='brand'>{html.escape(str(display_name))}</h1></div>"
    "<div class='sidebar-topbody'><div class='stack'>"
    f"<p>signed in as <strong>{html.escape(username)}</strong></p>"
    f"<p>role <code>{html.escape(role_name)}</code></p>"
    f"{superuser_scope_toggle_html}"
    f"<p>active session <code>{html.escape(session_id)}</code></p>"
    f"<p>default target <code>{html.escape(default_target)}</code></p>"
    "</div></div>"
    "</section>"
    "<section class='sidebar-middle'>"
    "<div class='session-list-shell'>"
    "<div class='session-header'><button id='session-map-toggle' class='session-header-button' type='button'>"
    "<div><div class='sidebar-label'>Sessions</div><h2>Sessions</h2></div><p>Open Session Map</p></button></div>"
    f"<div class='talk-nav-list'>{session_nav_items}</div>"
    "</div>"
    "<form id='session-create-form' method='post' action='/sessions' class='session-create'>"
    "<div class='sidebar-label'>New Session</div>"
    "<input name='label' placeholder='New session label'>"
    "<button class='ghost' type='submit'>Create Session</button></form>"
    "</section>"
    "<section class='sidebar-bottom'>"
    "<div class='sidebar-bottombar'><div class='sidebar-label'>Footer</div>"
    "<form method='post' action='/logout'><button class='ghost' type='submit'>Logout</button></form></div>"
    "<div class='sidebar-bottombody'>"
    f"{sidebar_system_html}"
    "<section class='api'>"
    "<div>JSON API</div>"
    "<div><code>GET /messages</code> <code>GET /events</code> <code>GET /sessions</code></div>"
    "<div><code>POST /message</code> <code>POST /compact</code> <code>POST /usage</code> <code>POST /sessions</code> <code>POST /session/select</code> <code>POST /session/rename</code></div>"
