    "const normalizeRecentMessagesLimit = (value) => {"
    "const parsed = Number.parseInt(String(value ?? '').trim(), 10);"
    "if (!Number.isFinite(parsed) || parsed < 1) return defaultRecentMessagesLimit;"
    "return Math.min(maxRecentMessagesLimit, parsed);"
    "};"
    "let recentMessagesLimit = normalizeRecentMessagesLimit(localStorage.getItem(recentMessagesLimitStorageKey) || defaultRecentMessagesLimit);"
    "const computeEntryFetchLimit = () => Math.min(maxRecentMessagesLimit, Math.max(recentMessagesLimit * 4, defaultRecentMessagesLimit));"
