    "if (settingsButton) { settingsButton.classList.toggle('is-active', nextOpen); settingsButton.classList.toggle('ghost', !nextOpen); settingsButton.setAttribute('aria-expanded', nextOpen ? 'true' : 'false'); }"
    "if (nextOpen) {"
    "setGoalPopoverOpen(false);"
    "if (settingsEditorStatus) settingsEditorStatus.textContent = 'Session schedule settings are session-scoped.';"
    "}"
    "};"
    "window.setSettingsPopoverOpen = setSettingsPopoverOpen;"
    "const sessionScopeQuery = () => (isSuperuser && sessionScope === 'all') ? 'scope=all' : '';"
    "const sessionPathFor = (sid) => {"
    "const params = new URLSearchParams();"
    "if (sid) params.set('session_id', sid);"
    "if (isSuperuser && sessionScope === 'all') params.set('scope', 'all');"
    "const query = params.toString();"
    "return query ? `/?${query}` : '/';"
    "};"
    "const closeSessionMap = () => {"
    "setSessionMapOpen(false);"
    "history.replaceState(null, '', sessionPathFor(activeSessionId));"
    "};"
    "const openSessionMap = () => {"
    "setSessionMapOpen(true);"
    "history.replaceState(null, '', sessionPathFor(''));"
    "goalBoardLoading.classList.remove('is-hidden');"
    "goalBoardGrid.classList.add('is-loading');"
    "refreshSessionIndex();"
    "refreshTalkBoard();"
    "};"
    "const toggleSessionMap = () => {"
    "if (sessionMapOpen) closeSessionMap();"
    "else openSessionMap();"
    "};"
    "const toggleGoalPopover = () => {"
    "setGoalPopoverOpen(!goalPopoverOpen);"
    "renderViewMode();"
    "};"
    "/* Bind critical UI controls early so they keep working even if later"
    "   non-critical initialization hits a runtime error. */"
    "sessionMapToggle.onclick = (event) => { event.preventDefault(); toggleSessionMap(); };"
    "viewGoalButton.onclick = (event) => { event.preventDefault(); toggleGoalPopover(); };"
    "const viewSettingsButton = document.getElementById('view-settings');"
    "if (viewSettingsButton) { viewSettingsButton.onclick = (event) => { event.preventDefault(); setSettingsPopoverOpen(settingsPopover ? settingsPopover.classList.contains('is-hidden') : true); }; }"
    "goalCloseButton.onclick = (event) => { event.preventDefault(); setGoalPopoverOpen(false); viewGoalButton.focus(); };"
    "if (settingsCloseButton && viewSettingsButton) { settingsCloseButton.onclick = (event) => { event.preventDefault(); setSettingsPopoverOpen(false); viewSettingsButton.focus(); }; }"
    "document.addEventListener('click', (event) => {"
    "const button = event.target instanceof Element ? event.target.closest('[data-agent-controls-button=\"1\"]') : null;"
    "if (!button) return;"
    "event.preventDefault();"
    "event.stopPropagation();"
    "const serviceId = String(button.dataset.agentServiceId || '').trim();"
    "setAgentPopoverOpen(true, serviceId);"
    "}, true);"
    "document.addEventListener('click', (event) => {"
    "const target = event.target instanceof Element ? event.target.closest('#goal-save-button,#goal-toggle-button,#goal-reset-completed-button,#settings-save-button,#settings-close-button,#agent-welcome-button,#manual-compact-button') : null;"
    "if (!target) return;"
    "event.preventDefault();"
    "event.stopPropagation();"
    "const id = String(target.id || '');"
    "if (id === 'goal-save-button' && window.handleGoalSave) { window.handleGoalSave(); return; }"
    "if (id === 'goal-toggle-button' && window.handleGoalToggle) { window.handleGoalToggle(); return; }"
    "if (id === 'goal-reset-completed-button' && window.handleGoalResetCompleted) { window.handleGoalResetCompleted(); return; }"
    "if (id === 'settings-save-button' && window.handleSettingsSave) { window.handleSettingsSave(); return; }"
    "if (id === 'settings-close-button' && window.setSettingsPopoverOpen) { window.setSettingsPopoverOpen(false); return; }"
    "if (id === 'agent-welcome-button' && window.handleAgentWelcome) { window.handleAgentWelcome(); return; }"
    "if (id === 'manual-compact-button' && window.handleManualCompact) { window.handleManualCompact(); return; }"
    "}, true);"
    "document.addEventListener('change', (event) => {"
    "const target = event.target instanceof Element ? event.target.closest('#goal-reset-on-prompt-toggle,#goal-auto-compact-toggle,#goal-agent-welcome-toggle,#provider-select,#auto-compact-threshold,#settings-auto-resume-enabled,#settings-auto-resume-interval') : null;"
    "if (!target) return;"
    "const id = String(target.id || '');"
    "if (id === 'goal-reset-on-prompt-toggle' && window.handleGoalResetOnPromptToggle) { window.handleGoalResetOnPromptToggle(); return; }"
    "if (id === 'goal-auto-compact-toggle' && window.handleGoalAutoCompactToggle) { window.handleGoalAutoCompactToggle(); return; }"
    "if (id === 'goal-agent-welcome-toggle' && window.handleGoalAgentWelcomeToggle) { window.handleGoalAgentWelcomeToggle(); return; }"
    "if (id === 'provider-select' && window.handleProviderSelectChange) { window.handleProviderSelectChange(); return; }"
    "if (id === 'auto-compact-threshold' && window.handleAutoCompactThresholdChange) { window.handleAutoCompactThresholdChange(); return; }"
    "if ((id === 'settings-auto-resume-enabled' || id === 'settings-auto-resume-interval') && window.handleSettingsSave) { window.handleSettingsSave(); return; }"
    "}, true);"
    "const setAgentPopoverOpen = (open, serviceId = activeAgentPopoverServiceId) => {"
    "activeAgentPopoverServiceId = String(serviceId || boundServiceId || '').trim();"
    "agentPopoverOpen = Boolean(open);"
    "agentPopover.classList.toggle('is-hidden', !agentPopoverOpen);"
    "const boundAgentButton = document.getElementById('open-bound-agent-controls');"
    "if (boundAgentButton) {"
    "boundAgentButton.classList.toggle('is-active', agentPopoverOpen);"
    "boundAgentButton.classList.toggle('ghost', !agentPopoverOpen);"
    "boundAgentButton.setAttribute('aria-expanded', agentPopoverOpen ? 'true' : 'false');"
    "}"
    "if (!agentPopoverOpen) return;"
    "const isWritableAgent = Boolean(activeAgentPopoverServiceId) && activeAgentPopoverServiceId === boundServiceId;"
    "agentPopoverTitle.textContent = activeAgentPopoverServiceId ? `Agent Controls: ${agentServiceLabel(activeAgentPopoverServiceId)}` : 'Agent Controls';"
    "agentPopoverCopy.textContent = isWritableAgent ? 'This is the currently bound agent for the session, so compact and threshold changes apply here.' : 'This agent is shown read-only right now. Writable compact controls stay attached to the currently bound agent.';"
    "manualCompactButton.disabled = !isWritableAgent;"
    "autoCompactThresholdSlider.disabled = !isWritableAgent;"
    "renderContextStatus();"
    "renderAgentStatus();"
    "renderAutoCompactThreshold();"
    "};"
    "window.setAgentPopoverOpen = setAgentPopoverOpen;"
    "const providerLabel = () => preferredProvider === 'claude' ? 'Claude Code' : 'Codex';"
    "const auditStateLabel = (auditState) => auditState === 'needs_compact' ? 'Needs Compact' : (auditState === 'panic' ? 'Panic' : 'All Clear');"
    "const isAgentScopedStatusEventType = (eventType) => ['service.auto_compact_checked', 'service.auto_compact_failed', 'service.manual_compact_started', 'service.manual_compact_checked', 'service.manual_compact_failed', 'service.goal_manager_compact_started', 'service.goal_manager_compact_checked', 'service.goal_manager_compact_failed', 'service.progress_inquiry_requested', 'service.progress_inquiry_deferred', 'service.progress_inquiry_completed', 'service.progress_inquiry_failed'].includes(String(eventType || ''));"
    "const agentServiceLabel = (serviceId) => {"
    "const value = String(serviceId || '').trim();"
    "if (!value) return providerLabel();"
    "if (value.includes('claude')) return `Claude Code (${value})`;"
    "if (value.includes('codex')) return `Codex (${value})`;"
    "return value;"
    "};"
    "const escapeHtml = (value) => String(value || '').replaceAll('&', '&amp;').replaceAll('<', '&lt;').replaceAll('>', '&gt;').replaceAll('\"', '&quot;').replaceAll(\"'\", '&#39;');"
    "const goalBoardProviderLabel = (provider) => provider === 'claude' ? 'Claude' : 'Codex';"
    "const goalBoardActivityLabel = (summary) => summary?.goal_active ? 'Active' : 'Inactive';"
    "const goalBoardProgressLabel = (summary) => summary?.goal_completed ? 'Completed' : 'In Progress';"
    "const bridgeTitle = (value) => `${String(value || 'HttpBridge').trim() || 'HttpBridge'} | HttpBridge`;"
    "const applyGoalPayload = (payload, fallbackGoalText = goalTextValue) => {"
    "goalTextValue = Object.prototype.hasOwnProperty.call(payload || {}, 'goal_text') ? String(payload.goal_text || '') : fallbackGoalText;"
    "if (!goalEditorFocused && !goalEditorDirty) { goalEditorDirty = false; goalEditorText.value = goalTextValue; }"
    "goalActive = Boolean(payload?.goal_active ?? goalActive);"
    "goalCompleted = Boolean(payload?.goal_completed ?? goalCompleted);"
    "goalProgressState = String(payload?.goal_progress_state || (goalCompleted ? 'complete' : 'in_progress'));"
    "goalAuditState = String(payload?.goal_audit_state || goalAuditState || 'all_clear');"
    "goalManagerRuntimeState = String(payload?.goal_manager_state || goalManagerRuntimeState || 'idle');"
    "goalResetCompletedOnPrompt = Boolean(payload?.goal_reset_completed_on_prompt ?? goalResetCompletedOnPrompt);"
    "goalAutoCompactEnabled = Boolean(payload?.goal_auto_compact_enabled ?? goalAutoCompactEnabled);"
    "autoResumeEnabled = Boolean(payload?.auto_resume_enabled ?? autoResumeEnabled);"
    "autoResumeIntervalSeconds = Number.parseInt(String(payload?.auto_resume_interval_seconds ?? autoResumeIntervalSeconds), 10) || autoResumeIntervalSeconds || 21600;"
    "autoResumeNextAt = String(payload?.auto_resume_next_at || autoResumeNextAt || '');"
    "autoResumeReason = String(payload?.auto_resume_reason || autoResumeReason || '');"
    "agentWelcomeEnabled = Boolean(payload?.agent_welcome_enabled ?? agentWelcomeEnabled);"
    "preferredProvider = String(payload?.preferred_provider || preferredProvider || 'codex');"
    "sessionGroup = String(payload?.session_group || sessionGroup || 'user');"
    "if (payload?.context_status && typeof payload.context_status === 'object') contextStatus = payload.context_status;"
    "renderGoalState();"
    "renderContextStatus();"
    "renderGoalAuditIndicator();"
    "renderProviderState();"
    "if (settingsAutoResumeEnabled) settingsAutoResumeEnabled.checked = autoResumeEnabled;"
    "if (settingsAutoResumeInterval) settingsAutoResumeInterval.value = String(autoResumeIntervalSeconds || 21600);"
    "if (settingsSessionGroup) settingsSessionGroup.textContent = sessionGroup;"
    "if (settingsAutoResumeMeta) settingsAutoResumeMeta.textContent = autoResumeNextAt ? `Next resume: ${autoResumeNextAt}${autoResumeReason ? ` | ${autoResumeReason}` : ''}` : (autoResumeEnabled ? 'No resume currently scheduled.' : 'Scheduled auto resume is disabled.');"
    "renderAgentStatus();"
    "renderWelcomedAgents();"
    "};"
    "const postGoalStateJson = async (body) => {"
    "const response = await fetch('/session/goal/state', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ session_id: activeSessionId, ...body }) });"
    "const payload = await response.json().catch(() => ({}));"
    "if (!response.ok || !payload.ok) throw new Error(String(payload.error || `HTTP ${response.status}`));"
    "applyGoalPayload(payload);"
    "return payload;"
    "};"
    "window.handleGoalSave = async () => {"
    "if (goalMutationInFlight) return;"
    "const goalText = goalEditorText.value.trim();"
    "goalMutationInFlight = true;"
    "goalSaveButton.disabled = true;"
    "goalEditorStatus.textContent = 'Updating goal...';"
    "try {"
    "const response = await fetch('/session/goal', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ session_id: activeSessionId, goal_text: goalText }) });"
    "const payload = await response.json().catch(() => ({}));"
    "if (!response.ok || !payload.ok) throw new Error(String(payload.error || `HTTP ${response.status}`));"
    "applyGoalPayload(payload, goalText);"
    "const dispatchedTo = String(payload.dispatched_to || '').trim();"
    "const dispatchError = String(payload.dispatch_error || '').trim();"
    "goalEditorStatus.textContent = goalTextValue ? (dispatchedTo ? `Goal updated and queued for ${dispatchedTo}` : (dispatchError ? `Goal updated, but dispatch failed: ${dispatchError}` : 'Goal updated')) : 'Goal cleared';"
    "} catch (error) {"
    "goalEditorStatus.textContent = `Goal update failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "goalSaveButton.disabled = false;"
    "}"
    "};"
    "window.handleGoalToggle = async () => {"
    "if (goalMutationInFlight) return;"
    "const nextGoalActive = !goalActive;"
    "goalMutationInFlight = true;"
    "goalEditorStatus.textContent = goalActive ? 'Deactivating goal...' : 'Activating goal...';"
    "try {"
    "const payload = await postGoalStateJson({ goal_active: nextGoalActive });"
    "const dispatchedTo = String(payload.dispatched_to || '').trim();"
    "const dispatchError = String(payload.dispatch_error || '').trim();"
    "goalEditorStatus.textContent = dispatchedTo ? `${nextGoalActive ? 'Goal active' : 'Goal inactive'} and queued for ${dispatchedTo}` : (dispatchError ? `${nextGoalActive ? 'Goal active' : 'Goal inactive'}, but dispatch failed: ${dispatchError}` : (nextGoalActive ? 'Goal active' : 'Goal inactive'));"
    "} catch (error) {"
    "goalEditorStatus.textContent = `Goal state update failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "}"
    "};"
    "window.handleGoalResetCompleted = async () => {"
    "if (goalMutationInFlight) return;"
    "goalMutationInFlight = true;"
    "goalEditorStatus.textContent = 'Resetting completion...';"
    "try {"
    "const payload = await postGoalStateJson({ goal_completed: false });"
    "const dispatchedTo = String(payload.dispatched_to || '').trim();"
    "const dispatchError = String(payload.dispatch_error || '').trim();"
    "goalEditorStatus.textContent = dispatchedTo ? `Goal completion reset and queued for ${dispatchedTo}` : (dispatchError ? `Goal completion reset, but dispatch failed: ${dispatchError}` : 'Goal completion reset');"
    "} catch (error) {"
    "goalEditorStatus.textContent = `Reset failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "}"
    "};"
    "window.handleGoalResetOnPromptToggle = async () => {"
    "if (goalMutationInFlight) return;"
    "goalMutationInFlight = true;"
    "goalEditorStatus.textContent = 'Saving prompt reset setting...';"
    "try {"
    "await postGoalStateJson({ goal_reset_completed_on_prompt: goalResetOnPromptToggle.checked });"
    "goalEditorStatus.textContent = goalResetCompletedOnPrompt ? 'SendPrompt reset enabled' : 'SendPrompt reset disabled';"
    "} catch (error) {"
    "goalResetOnPromptToggle.checked = goalResetCompletedOnPrompt;"
    "goalEditorStatus.textContent = `Setting save failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "}"
    "};"
    "window.handleGoalAutoCompactToggle = async () => {"
    "if (goalMutationInFlight) return;"
    "goalMutationInFlight = true;"
    "goalEditorStatus.textContent = 'Saving GoalManager compact setting...';"
    "try {"
    "await postGoalStateJson({ goal_auto_compact_enabled: goalAutoCompactToggle.checked });"
    "goalEditorStatus.textContent = goalAutoCompactEnabled ? 'GoalManager autonomous compact enabled' : 'GoalManager autonomous compact disabled';"
    "} catch (error) {"
    "goalAutoCompactToggle.checked = goalAutoCompactEnabled;"
    "goalEditorStatus.textContent = `Setting save failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "}"
    "};"
    "window.handleGoalAgentWelcomeToggle = async () => {"
    "if (goalMutationInFlight) return;"
    "goalMutationInFlight = true;"
    "goalEditorStatus.textContent = 'Saving multi-agent setting...';"
    "try {"
    "await postGoalStateJson({ agent_welcome_enabled: goalAgentWelcomeToggle.checked });"
    "goalEditorStatus.textContent = agentWelcomeEnabled ? 'Multi-agent mode enabled' : 'Multi-agent mode disabled';"
    "} catch (error) {"
    "goalAgentWelcomeToggle.checked = agentWelcomeEnabled;"
    "goalEditorStatus.textContent = `Setting save failed: ${error}`;"
    "} finally {"
    "goalMutationInFlight = false;"
    "}"
    "};"
    "window.handleSettingsSave = async () => {"
    "if (!settingsSaveButton || !settingsAutoResumeEnabled || !settingsAutoResumeInterval || settingsMutationInFlight) return;"
    "settingsMutationInFlight = true;"
    "settingsSaveButton.disabled = true;"
    "settingsEditorStatus.textContent = 'Updating settings...';"
    "try {"
    "const payload = await postGoalStateJson({ auto_resume_enabled: settingsAutoResumeEnabled.checked, auto_resume_interval_seconds: Number.parseInt(String(settingsAutoResumeInterval.value || autoResumeIntervalSeconds || 21600), 10) || 21600 });"
    "const dispatchedTo = String(payload.dispatched_to || '').trim();"
    "const dispatchError = String(payload.dispatch_error || '').trim();"
    "settingsEditorStatus.textContent = dispatchedTo ? `Settings updated and queued for ${dispatchedTo}` : (dispatchError ? `Settings updated, but dispatch failed: ${dispatchError}` : 'Settings updated');"
    "} catch (error) {"
    "if (settingsAutoResumeEnabled) settingsAutoResumeEnabled.checked = autoResumeEnabled;"
    "if (settingsAutoResumeInterval) settingsAutoResumeInterval.value = String(autoResumeIntervalSeconds || 21600);"
    "settingsEditorStatus.textContent = `Settings update failed: ${error}`;"
    "} finally {"
    "settingsMutationInFlight = false;"
    "settingsSaveButton.disabled = false;"
    "}"
    "};"
    "const renderPageTitle = () => {"
    "document.title = bridgeTitle(sessionMapOpen ? 'Sessions' : talkLabel);"
    "};"
    "const captureSessionMapSnapshot = () => {"
    "sessionMapSnapshotTalkIds = (Array.isArray(talkSummaries) ? talkSummaries : []).map((summary) => String(summary?.session_id || '').trim()).filter(Boolean);"
    "};"
    "const setSessionMapOpen = (open) => {"
    "const nextOpen = Boolean(open);"
    "if (nextOpen && !sessionMapOpen) captureSessionMapSnapshot();"
    "if (!nextOpen) sessionMapSnapshotTalkIds = [];"
    "sessionMapOpen = nextOpen;"
    "mainTopbar.classList.toggle('is-hidden', sessionMapOpen);"
    "mainViewToolbar.classList.toggle('is-hidden', sessionMapOpen);"
    "mainPane.classList.toggle('is-map-open', sessionMapOpen);"
    "talkPane.classList.toggle('is-hidden', sessionMapOpen);"
    "sessionMapPane.classList.toggle('is-hidden', !sessionMapOpen);"
    "sessionMapToggle.classList.toggle('is-active', sessionMapOpen);"
    "const label = sessionMapToggle.querySelector('p');"
    "if (label) label.textContent = sessionMapOpen ? 'Close Session Map' : 'Open Session Map';"
    "renderPageTitle();"
    "renderViewMode();"
    "if (sessionMapOpen) renderGoalBoard();"
    "};"
    "let lastTalkNavRenderKey = '';"
    "let lastGoalBoardRenderKey = '';"
    "const talkNavRenderKey = (summaries) => JSON.stringify((Array.isArray(summaries) ? summaries : []).map((summary) => ({"
    "sid: String(summary?.session_id || ''),"
    "label: String(summary?.label || ''),"
    "active: Boolean(summary?.goal_active),"
    "completed: Boolean(summary?.goal_completed),"
    "selected: String(summary?.session_id || '') === String(activeSessionId || ''),"
    "})));"
    "const goalBoardRenderKey = (summaries) => JSON.stringify({"
    "open: Boolean(sessionMapOpen),"
    "active: String(activeSessionId || ''),"
    "snapshot: Array.isArray(sessionMapSnapshotTalkIds) ? sessionMapSnapshotTalkIds : [],"
    "workerCounts: workerCounts || {},"
    "cards: (Array.isArray(summaries) ? summaries : []).map((summary) => ({"
    "sid: String(summary?.session_id || ''),"
    "label: String(summary?.label || ''),"
    "goal: String(summary?.goal_text || ''),"
    "goal_active: Boolean(summary?.goal_active),"
    "goal_completed: Boolean(summary?.goal_completed),"
    "agent_running: Boolean(summary?.agent_running),"
    "goal_manager_state: String(summary?.goal_manager_state || ''),"
    "preferred_provider: String(summary?.preferred_provider || ''),"
    "worker_provider: String(summary?.worker?.provider || ''),"
    "worker_slot: summary?.worker?.slot == null ? null : String(summary?.worker?.slot),"
    "goal_worker_slot: summary?.goal_manager_worker?.slot == null ? null : String(summary?.goal_manager_worker?.slot),"
    "})),"
    "});"
    "const renderTalkNavList = () => {"
    "if (!talkNavList) return;"
    "const summaries = Array.isArray(talkSummaries) ? talkSummaries : [];"
    "const renderKey = talkNavRenderKey(summaries);"
    "if (renderKey === lastTalkNavRenderKey) return;"
    "lastTalkNavRenderKey = renderKey;"
    "const scrollState = captureElementScrollState(talkNavList);"
    "const nodes = summaries.map((summary) => {"
    "const sid = String(summary?.session_id || '').trim();"
    "if (!sid) return null;"
    "const isActive = sid === String(activeSessionId || '');"
    "const link = document.createElement('a');"
    "link.className = `talk-nav-item${isActive ? ' is-active' : ''}`;"
    "link.href = sessionPathFor(sid);"
    "link.addEventListener('click', (ev) => { ev.preventDefault(); switchToSession(sid); });"
    "const head = document.createElement('span');"
    "head.className = 'talk-nav-head';"
    "const title = document.createElement('span');"
    "title.className = 'talk-nav-title';"
    "title.textContent = String(summary?.label || sid);"
    "const signals = document.createElement('span');"
    "signals.className = 'talk-nav-signals';"
    "signals.setAttribute('aria-label', 'Session goal status');"
    "const activeSignal = document.createElement('span');"
    "activeSignal.className = `talk-signal talk-signal-active${summary?.goal_active ? ' is-on' : ''}`;"
    "activeSignal.textContent = '●';"
    "activeSignal.title = 'Goal active state';"
    "const completedSignal = document.createElement('span');"
    "completedSignal.className = `talk-signal talk-signal-completed${summary?.goal_completed ? ' is-on' : ''}`;"
    "completedSignal.textContent = '●';"
    "completedSignal.title = 'Goal completed state';"
    "signals.append(activeSignal, completedSignal);"
    "head.append(title, signals);"
    "const meta = document.createElement('span');"
    "meta.className = 'talk-nav-meta';"
    "meta.textContent = sid;"
    "link.append(head, meta);"
    "return link;"
    "}).filter(Boolean);"
    "talkNavList.replaceChildren(...nodes);"
    "restoreElementScrollPosition(talkNavList, scrollState);"
    "};"
    "const goalBoardCountsText = () => {"
    "const codex = workerCounts?.codex || {};"
    "const claude = workerCounts?.claude || {};"
    "return `Codex ${String(codex.running || 0)} active / ${String(codex.active_turns || 0)} replying | Claude ${String(claude.running || 0)} active / ${String(claude.active_turns || 0)} replying`;"
    "};"
    "const renderGoalBoard = () => {"
    "const talkSummariesList = Array.isArray(talkSummaries) ? talkSummaries : [];"
    "const renderKey = goalBoardRenderKey(talkSummariesList);"
    "if (renderKey === lastGoalBoardRenderKey) return;"
    "lastGoalBoardRenderKey = renderKey;"
    "const scrollState = captureElementScrollState(goalBoardGrid);"
    "goalBoardCounts.replaceChildren();"
    "for (const provider of ['codex', 'claude']) {"
    "const item = workerCounts?.[provider] || {};"
    "const pill = document.createElement('div');"
    "pill.className = `goal-worker-pill${provider === 'claude' ? ' is-claude' : ''}`;"
    "pill.innerHTML = `<span class='goal-worker-dot'></span><span>${goalBoardProviderLabel(provider)}</span><strong>${String(item.running || 0)}</strong><span>${String(item.active_turns || 0)} replying</span>`;"
    "goalBoardCounts.appendChild(pill);"
    "}"
    "goalBoardMeta.textContent = goalBoardCountsText();"
    "const talkSummariesById = new Map(talkSummariesList.map((summary) => [String(summary?.session_id || '').trim(), summary]));"
    "const visibleTalkSummaries = sessionMapOpen && sessionMapSnapshotTalkIds.length ? sessionMapSnapshotTalkIds.map((talkId) => talkSummariesById.get(talkId)).filter(Boolean) : talkSummariesList;"
    "const cards = visibleTalkSummaries.map((summary) => {"
    "const link = document.createElement('a');"
    "const worker = summary?.worker || null;"
    "const workerProvider = String(worker?.provider || summary?.preferred_provider || 'codex');"
    "const workerSlot = worker?.slot == null ? '·' : String(worker.slot);"
    "const goalWorker = summary?.goal_manager_worker || null;"
    "const goalWorkerSlot = goalWorker?.slot == null ? '·' : String(goalWorker.slot);"
    "link.className = 'goal-session-card';"
    "if (String(summary?.session_id || '') === activeSessionId) link.classList.add('is-active-talk');"
    "if (summary?.agent_running) link.classList.add('is-agent-running');"
    "if (String(summary?.goal_manager_state || '') === 'running') link.classList.add('is-goal-running');"
    "if (!summary?.goal_active) link.classList.add('is-goal-inactive');"
    "link.href = sessionPathFor(String(summary?.session_id || summary?.session_id || ''));"
    "link.title = 'Open this session';"
    "link.addEventListener('click', (ev) => { ev.preventDefault(); switchToSession(String(summary?.session_id || '')); });"
    "const leftMarker = `<span class='goal-marker goal-marker-left${workerProvider === 'claude' ? ' is-claude' : ''}${summary?.worker ? '' : ' is-idle'}' title='${summary?.agent_running ? 'Agent replying now' : 'Bound/selected worker'}'>${workerSlot}</span>`;"
    "const rightMarker = `<span class='goal-marker goal-marker-right${String(summary?.goal_manager_state || '') === 'running' ? '' : ' is-hidden'}' title='GoalManager running'>${goalWorkerSlot}</span>`;"
    "const goalText = String(summary?.goal_text || '').trim();"
    "const goalHtml = goalText ? escapeHtml(goalText) : `<span class='goal-session-empty'>No goal</span>`;"
    "link.innerHTML = `${leftMarker}${rightMarker}<div class='goal-session-card-head'><div class='goal-session-title'>${escapeHtml(summary?.label || summary?.session_id || '')}</div></div><div class='goal-session-meta'>${escapeHtml(summary?.username ? summary.username + ' · ' : '')}${escapeHtml(summary?.session_id || '')}</div><div class='goal-session-goal'>${goalHtml}</div><div class='goal-session-state'><span class='goal-session-badge${summary?.goal_active ? ' is-on' : ''}'>${goalBoardActivityLabel(summary)}</span><span class='goal-session-badge${summary?.goal_completed ? ' is-done' : ''}'>${goalBoardProgressLabel(summary)}</span></div>`;"
    "return link;"
    "});"
    "goalBoardGrid.replaceChildren(...cards);"
    "restoreElementScrollPosition(goalBoardGrid, scrollState);"
    "};"
    "const refreshSessionMapSnapshot = (nextTalkSummaries) => {"
    "if (!sessionMapOpen) return;"
    "if (!Array.isArray(nextTalkSummaries)) return;"
    "const nextSessionIds = new Set("
    "nextTalkSummaries"
    "    .map((summary) => String(summary?.session_id || '').trim())"
    "    .filter(Boolean),"
    ");"
    "const mergedSessionIds = new Set(sessionMapSnapshotTalkIds);"
    "for (const sessionId of nextSessionIds) {"
