    "sessionMapSnapshotTalkIds = Array.from(mergedSessionIds);"
    "};"
    "let _refreshSessionIndexInFlight = false;"
    "const refreshSessionIndex = async () => {"
    "if (_refreshSessionIndexInFlight) return;"
    "_refreshSessionIndexInFlight = true;"
    "try {"
    "const scopeQuery = sessionScopeQuery();"
    "const response = await fetch(`/sessions?${scopeQuery}${scopeQuery ? '&' : ''}_=${Date.now()}`, { cache: 'no-store' });"
    "const payload = await response.json().catch(() => ({}));"
    "if (!response.ok) return;"
    "if (Array.isArray(payload.session_summaries)) {"
    "talkSummaries = payload.session_summaries;"
    "renderTalkNavList();"
