    "} finally {"
    "_refreshSessionIndexInFlight = false;"
    "}"
    "};"
    "const renderProviderState = () => {"
    "providerSelect.value = preferredProvider;"
    "providerStatus.textContent = preferredProvider === 'claude' ? 'This session will dispatch new prompts to Claude Code workers.' : 'This session will dispatch new prompts to Codex workers.';"
    "manualCompactButton.disabled = false;"
    "};"
    "const renderAgentStatus = () => {"
    "const popoverServiceId = String(activeAgentPopoverServiceId || boundServiceId || '').trim();"
    "const isWritableAgent = Boolean(popoverServiceId) && popoverServiceId === boundServiceId;"
    "agentStatusValue.textContent = `${popoverServiceId && popoverServiceId.includes('claude') ? 'Claude Code' : providerLabel()} | ${auditStateLabel(goalAuditState)}`;"
    "const bits = [popoverServiceId ? `agent ${popoverServiceId}` : 'No bound service'];"
    "if (goalAuditState === 'needs_compact') bits.push('Compact requested before normal continuation');"
    "else if (goalAuditState === 'panic') bits.push('Dispatch is blocked until recovery');"
    "else bits.push('Agent can continue processing this session');"
    "if (!isWritableAgent) bits.push('read-only view');"
    "agentStatusMeta.textContent = bits.join(' | ');"
    "};"
    "const deriveAgentMessageEventText = (entry) => {"
    "if (!entry || !entry.event || entry.event_type !== 'item.completed') return null;"
    "const item = entry.event.item;"
    "if (!item || item.type !== 'agent_message') return null;"
    "const raw = String(item.text || '').trim();"
    "if (!raw) return '';"
    "try { const parsed = JSON.parse(raw); if (parsed && typeof parsed.assistant_text === 'string') return parsed.assistant_text.trim(); } catch (_error) {}"
    "return raw;"
    "};"
    "const shouldRenderEventJson = (entry) => {"
    "if (!entry || !entry.event) return false;"
    "return deriveAgentMessageEventText(entry) === null;"
    "};"
    "const entryDisplayText = (entry) => {"
    "const agentText = deriveAgentMessageEventText(entry);"
    "if (agentText !== null) return agentText;"
    "return entry.text || '';"
    "};"
    "const extractGoalEventType = (entry) => String(entry?.event_type || (entry?.event && entry.event.type) || '');"
    "const isGoalManagerEntry = (entry) => {"
    "const eventType = extractGoalEventType(entry);"
    "return eventType.startsWith('service.goal_') || eventType.startsWith('service.goal_manager_compact_') || eventType === 'service.post_turn_followup_started' || eventType === 'service.post_turn_followup_failed';"
    "};"
    "const plainBlockKind = (entry) => {"
    "const direction = String(entry?.direction || '').trim();"
    "if (direction === 'out' || direction === 'user') return 'user_block';"
    "if (direction === 'session_input') return 'system_block';"
    "if ((direction === 'event' || direction === 'agent') && !isGoalManagerEntry(entry) && !isAgentTurnRelatedEntry(entry)) return 'system_block';"
    "return null;"
    "};"
    "const renderEntry = (entry) => {"
    "const li = document.createElement('li');"
    "const goalManagerEntry = isGoalManagerEntry(entry);"
    "li.className = `entry ${goalManagerEntry ? 'entry-goal-manager' : `entry-${entry.direction || 'event'}`}`;"
    "const bubble = document.createElement('div');"
    "bubble.className = 'bubble';"
    "if (entry.context_left_percent !== undefined) { const badge = document.createElement('div'); badge.className = 'ctx-badge'; const bits = [`${entry.context_left_percent}% left`]; if (entry.context_compaction) bits.push(entry.context_compaction); badge.textContent = bits.join(' | '); bubble.appendChild(badge); }"
    "const role = document.createElement('div');"
    "role.className = 'role';"
    "const normalizedDirection = String(entry.direction || '').trim();"
    "role.textContent = goalManagerEntry ? 'GoalManager' : (({"
    "    out: 'User',"
    "    user: 'User',"
    "    in: 'CodexFox',"
    "    event: 'Event',"
    "    agent: 'AgentMessage',"
    "    session_input: 'SessionInput',"
    "})[normalizedDirection || 'event'] || normalizedDirection || 'event');"
    "bubble.appendChild(role);"
    "const text = document.createElement('div');"
