    "if (entry.to) metaBits.push(`to ${entry.to}`);"
    "if (metaBits.length) { const meta = document.createElement('div'); meta.className = 'meta'; meta.textContent = metaBits.join(' | '); bubble.appendChild(meta); }"
    "if (shouldRenderEventJson(entry)) { const pre = document.createElement('pre'); pre.className = 'event-json'; pre.textContent = JSON.stringify(entry.event, null, 2); bubble.appendChild(pre); }"
    "li.appendChild(bubble);"
