    "};"
    "const entryServiceId = (entry) => String(entry?.service_id || entry?.from || '').trim();"
    "const isAgentTurnRelatedEntry = (entry) => {"
    "if (!entry || isGoalManagerEntry(entry) || entry.direction === 'out') return false;"
    "const eventType = String(entry?.event_type || '');"
    "if (entry.direction === 'in' || entry.direction === 'session_input') return Boolean(entryServiceId(entry));"
    "if (entry.direction === 'event' || entry.direction === 'agent') {"
    "return Boolean(entryServiceId(entry)) || eventType === 'usage' || String(eventType).startsWith('service.');"
    "}"
    "return false;"
    "};"
    "const turnLogLabel = (entry) => {"
    "const eventType = String(entry?.event_type || '');"
    "if (eventType === 'agent.turn_started') return 'response started';"
    "if (eventType === 'thread.started') return 'thread started';"
    "if (eventType === 'turn.started') return 'turn started';"
    "if (eventType === 'turn.completed') return 'turn completed';"
    "if (eventType.startsWith('item.')) return eventType;"
