    "const goalManagerClusterState = (cluster) => {"
    "const lastEntry = cluster.entries[cluster.entries.length - 1] || null;"
    "const eventType = String(lastEntry?.event_type || '');"
    "if (eventType === 'service.goal_audit_failed' || eventType === 'service.post_turn_followup_failed' || eventType === 'service.goal_manager_compact_failed') return { text: 'Failed', className: 'is-signal-red', meta: 'GoalManager review hit an error' };"
    "if (eventType === 'service.goal_audit_completed') return { text: 'Completed', className: 'is-complete', meta: 'GoalManager finished this review cycle' };"
    "const hasParseRetry = cluster.entries.some((e) => String(e?.event_type || '').includes('goal_audit_parse_retry'));"
    "if (hasParseRetry) return { text: 'Parse Retry', className: 'is-signal-yellow', meta: 'GoalManager output could not be parsed; retrying' };"
    "return { text: 'Reviewing', className: 'is-signal-blue', meta: 'GoalManager is actively reviewing this session' };"
    "};"
    "const agentInlineStatusBits = (cluster) => {"
    "const status = deriveContextStatusForService(cluster.serviceId) || (cluster.serviceId === boundServiceId ? (contextStatus || {}) : {});"
    "const bits = [];"
    "if (status.left_percent) bits.push(`${String(status.left_percent)}% left`);"
