    "if (cluster.serviceId === boundServiceId) bits.push(`audit ${auditStateLabel(goalAuditState)}`);"
    "if (cluster.serviceId && boundServiceId && cluster.serviceId !== boundServiceId) bits.push('read-only');"
    "return bits;"
    "};"
    "const renderTurnCluster = (cluster) => {"
    "const li = document.createElement('li');"
