    "providerBadge.className = 'goal-badge';"
    "providerBadge.textContent = isGoalManagerCluster ? 'GoalManager' : (cluster.serviceId && cluster.serviceId.includes('claude') ? 'Claude Code' : 'Codex');"
    "badges.appendChild(providerBadge);"
    "if (!isGoalManagerCluster && cluster.serviceId && boundServiceId && cluster.serviceId === boundServiceId) {"
    "const auditBadge = document.createElement('span');"
