    "progressBadge.className = `goal-badge ${state.className}`;"
    "progressBadge.textContent = state.text;"
    "} else {"
    "progressBadge.className = `goal-badge${cluster.completed ? ' is-complete' : ''}`;"
    "progressBadge.textContent = cluster.completed ? 'TurnCompleted' : 'In Progress';"
