    "if (!isGoalManagerCluster) {"
    "const sessionEntries = cluster.entries.filter((e) => e.direction === 'session_input');"
    "if (sessionEntries.length > 0) {"
    "const sessionShell = document.createElement('details');"
    "sessionShell.className = 'turn-cluster-events turn-cluster-session';"
