    "labelBadge.textContent = isUserBlock ? 'User' : 'FIFO / Event';"
    "badges.appendChild(labelBadge);"
    "const countBadge = document.createElement('span');"
    "countBadge.className = 'goal-badge';"
    "countBadge.textContent = `${cluster.entries.length} ${cluster.entries.length === 1 ? 'entry' : 'entries'}`;"
    "badges.appendChild(countBadge);"
    "head.appendChild(badges);"
    "bubble.appendChild(head);"
    "const latest = cluster.entries[cluster.entries.length - 1] || {};"
    "const reply = document.createElement('div');"
    "reply.className = 'turn-cluster-reply';"
    "reply.textContent = entryDisplayText(latest);"
    "bubble.appendChild(reply);"
    "const eventsShell = document.createElement('details');"
    "eventsShell.className = 'turn-cluster-events';"
    "const eventsHead = document.createElement('summary');"
    "eventsHead.className = 'turn-cluster-events-head turn-cluster-events-toggle';"
    "const eventsTitle = document.createElement('span');"
    "eventsTitle.textContent = 'Block Log';"
    "eventsHead.appendChild(eventsTitle);"
    "const eventsCount = document.createElement('span');"
    "eventsCount.textContent = `${cluster.entries.length} entries`;"
    "eventsHead.appendChild(eventsCount);"
    "eventsShell.appendChild(eventsHead);"
    "const log = document.createElement('div');"
    "log.className = 'turn-cluster-log';"
    "log.dataset.scrollKey = clusterRenderKey(cluster);"
    "for (const blockEntry of cluster.entries) {"
    "const row = document.createElement('div');"
    "row.className = 'turn-cluster-log-entry';"
    "const rowHead = document.createElement('div');"
    "rowHead.className = 'turn-cluster-log-entry-head';"
