    "};"
    "const buildRenderableTimeline = (items) => {"
    "const ascending = items.slice().sort((left, right) => String(left?.ts || '').localeCompare(String(right?.ts || '')));"
    "const timeline = [];"
    "const agentClusters = new Map();"
    "let goalCluster = null;"
    "let plainCluster = null;"
    "const finalizeCluster = (sid) => { const c = agentClusters.get(sid); if (!c) return; timeline.push(c); agentClusters.delete(sid); };"
    "const finalizeAllClusters = () => { for (const sid of [...agentClusters.keys()]) finalizeCluster(sid); };"
    "const finalizeGoalCluster = () => { if (!goalCluster) return; timeline.push(goalCluster); goalCluster = null; };"
    "const finalizePlainCluster = () => { if (!plainCluster) return; timeline.push(plainCluster); plainCluster = null; };"
    "for (const entry of ascending) {"
    "const eventType = String(entry?.event_type || '');"
    "const serviceId = entryServiceId(entry);"
    "if (isGoalManagerEntry(entry)) {"
    "finalizePlainCluster();"
    "finalizeAllClusters();"
    "if (!goalCluster) goalCluster = { kind: 'goal_manager_cluster', entries: [] };"
    "goalCluster.entries.push(entry);"
    "continue;"
    "}"
    "finalizeGoalCluster();"
    "const plainKind = plainBlockKind(entry);"
    "if (plainKind) {"
    "finalizeAllClusters();"
    "if (plainCluster && plainCluster.kind !== plainKind) finalizePlainCluster();"
    "if (!plainCluster) plainCluster = { kind: plainKind, entries: [] };"
    "plainCluster.entries.push(entry);"
    "continue;"
    "}"
    "finalizePlainCluster();"
    "if (!isAgentTurnRelatedEntry(entry)) {"
    "timeline.push(entry);"
    "continue;"
    "}"
    "if (eventType === 'agent.turn_started') {"
    "const existing = agentClusters.get(serviceId);"
    "const isEmptyTurnStartedCluster = existing && !existing.replyEntry && !existing.completed && existing.entries.length === 1 && String(existing.entries[0]?.event_type || '') === 'agent.turn_started';"
    "if (isEmptyTurnStartedCluster) { existing.entries = [entry]; } else { if (existing) finalizeCluster(serviceId); agentClusters.set(serviceId, { kind: 'turn_cluster', serviceId, entries: [entry], replyEntry: null, completed: false }); }"
    "continue;"
    "}"
    "let cluster = agentClusters.get(serviceId);"
    "if (!cluster) {"
    "if (serviceId && (entry.direction === 'in' || entry.direction === 'session_input' || entry.direction === 'event' || entry.direction === 'agent')) {"
    "cluster = { kind: 'turn_cluster', serviceId, entries: [], replyEntry: null, completed: false };"
    "agentClusters.set(serviceId, cluster);"
    "} else {"
    "timeline.push(entry);"
    "continue;"
    "}"
    "} else if (cluster.completed && !isAgentScopedStatusEventType(eventType)) {"
    "finalizeCluster(serviceId);"
    "if (serviceId && (entry.direction === 'in' || entry.direction === 'session_input' || entry.direction === 'event' || entry.direction === 'agent')) {"
    "cluster = { kind: 'turn_cluster', serviceId, entries: [], replyEntry: null, completed: false };"
    "agentClusters.set(serviceId, cluster);"
    "} else {"
    "timeline.push(entry);"
    "continue;"
    "}"
    "}"
    "cluster.entries.push(entry);"
    "if (eventType === 'turn.completed') { cluster.completed = true; finalizeCluster(serviceId); } else if (entry.direction === 'in') { cluster.replyEntry = entry; }"
    "}"
    "finalizeAllClusters();"
    "finalizeGoalCluster();"
    "finalizePlainCluster();"
    "return timeline.reverse();"
    "};"
    "const deriveContextStatusForService = (serviceId) => {"
    "const targetServiceId = String(serviceId || '').trim();"
    "for (const entry of entries) {"
    "if (targetServiceId && entryServiceId(entry) !== targetServiceId) continue;"
    "const eventType = String(entry.event_type || '');"
    "const compaction = String(entry.context_compaction || '');"
    "const preLeft = entry.context_left_percent;"
    "const postLeft = entry.context_post_left_percent;"
    "const left = postLeft ?? preLeft;"
    "if ((eventType === 'service.auto_compact_checked' || eventType === 'service.manual_compact_checked') && compaction === 'triggered') {"
    "if (postLeft === undefined || String(postLeft) === String(preLeft ?? '')) {"
    "return {"
    "label: 'Context compacted',"
    "meta: 'Waiting for next context check to refresh the percentage',"
    "compaction,"
    "event_type: eventType,"
    "};"
    "}"
    "}"
    "if (left === undefined) continue;"
    "return {"
    "label: `Context ${String(left)}% left`,"
    "meta: '',"
    "left_percent: String(left),"
    "used_percent: String(entry.context_post_used_percent ?? entry.context_used_percent ?? ''),"
    "compaction,"
    "event_type: eventType,"
    "};"
    "}"
    "return null;"
    "};"
    "const deriveContextStatus = () => deriveContextStatusForService(activeAgentPopoverServiceId || boundServiceId);"
    "const renderContextStatus = () => {"
    "const popoverServiceId = String(activeAgentPopoverServiceId || boundServiceId || '').trim();"
    "const derivedStatus = deriveContextStatusForService(popoverServiceId);"
    "const fallbackStatus = (contextStatus && typeof contextStatus === 'object') ? contextStatus : null;"
    "const resolvedStatus = derivedStatus || fallbackStatus;"
    "if (derivedStatus) contextStatus = derivedStatus;"
    "if (!resolvedStatus) {"
    "contextStatusValue.textContent = 'Context unknown';"
    "contextStatusMeta.textContent = 'AutoCompact waits for first check';"
    "return;"
    "}"
    "contextStatusValue.textContent = resolvedStatus.label || 'Context unknown';"
    "const bits = [];"
    "if (resolvedStatus.meta) bits.push(resolvedStatus.meta);"
    "if (resolvedStatus.compaction) bits.push(`Compaction ${resolvedStatus.compaction}`);"
    "if (resolvedStatus.event_type) bits.push(resolvedStatus.event_type);"
    "contextStatusMeta.textContent = bits.join(' | ') || 'Latest agent-scoped context check';"
    "};"
    "const applyFilterButtons = () => {"
