    "goalResetCompletedOnPrompt = Boolean(payload.goal_reset_completed_on_prompt ?? true);"
    "goalAutoCompactEnabled = Boolean(payload.goal_auto_compact_enabled ?? true);"
    "agentWelcomeEnabled = Boolean(payload.agent_welcome_enabled ?? false);"
    "if (Array.isArray(payload.welcomed_agents)) welcomedAgents = payload.welcomed_agents;"
    "preferredProvider = String(payload.preferred_provider || preferredProvider || 'codex');"
