    "};"
    "const updateLatestExchangeSummary = () => {"
    "const latestPromptEntry = entries.find((entry) => String(entry?.direction || '').trim() === 'out' || String(entry?.direction || '').trim() === 'user');"
    "const latestReplyEntry = entries.find((entry) => String(entry?.direction || '').trim() === 'in');"
    "if (latestUserPrompt) latestUserPrompt.textContent = latestPromptEntry ? entryDisplayText(latestPromptEntry) : 'No recent prompt recorded.';"
    "if (latestAgentReply) latestAgentReply.textContent = latestReplyEntry ? entryDisplayText(latestReplyEntry) : 'No recent agent reply recorded.';"
    "};"
    "const filteredEntries = () => {"
    "return entries.slice();"
    "};"
    "const selectVisibleTimeline = (timeline) => {"
    "const visible = timeline.slice(0, recentMessagesLimit);"
    "const latestGoalManagerCluster = timeline.find((entry) => entry?.kind === 'goal_manager_cluster') || null;"
    "if (latestGoalManagerCluster && !visible.includes(latestGoalManagerCluster)) visible.push(latestGoalManagerCluster);"
    "return visible;"
    "};"
    "const clusterRenderKey = (cluster) => {"
    "const entries = Array.isArray(cluster?.entries) ? cluster.entries : [];"
    "const firstEntry = entries[0] || {};"
    "const lastEntry = entries[entries.length - 1] || {};"
    "return ["
    "cluster.kind || 'entry',"
    "cluster.serviceId || '',"
    "String(entries.length || 0),"
    "String(firstEntry.ts || ''),"
    "String(firstEntry.event_type || ''),"
    "String(firstEntry.direction || ''),"
    "String(lastEntry.ts || ''),"
    "String(lastEntry.event_type || ''),"
    "String(lastEntry.direction || ''),"
    "String(lastEntry.text || '').slice(0, 120),"
    "].join('|');"
    "};"
    "const timelineSignature = (timeline) => {"
    "const head = timeline.slice(0, 12).map((entry) => {"
    "if (entry?.kind === 'turn_cluster' || entry?.kind === 'goal_manager_cluster' || entry?.kind === 'user_block' || entry?.kind === 'system_block') return clusterRenderKey(entry);"
    "return [String(entry?.ts || ''), String(entry?.event_type || ''), String(entry?.direction || ''), String(entry?.service_id || entry?.from || entry?.to || '')].join('|');"
    "});"
    "const tailEntry = timeline[timeline.length - 1] || null;"
    "const tail = tailEntry ? ((tailEntry?.kind === 'turn_cluster' || tailEntry?.kind === 'goal_manager_cluster' || tailEntry?.kind === 'user_block' || tailEntry?.kind === 'system_block') ? clusterRenderKey(tailEntry) : [String(tailEntry?.ts || ''), String(tailEntry?.event_type || ''), String(tailEntry?.direction || ''), String(tailEntry?.service_id || tailEntry?.from || tailEntry?.to || '')].join('|')) : '';"
    "return JSON.stringify({ filter: currentFilter, goalAuditState, goalProgressState, count: timeline.length, head, tail });"
    "};"
    "const captureElementScrollState = (element) => element ? ({"
    "top: element.scrollTop,"
    "height: element.scrollHeight,"
    "clientHeight: element.clientHeight,"
    "}) : null;"
    "const restoreElementScrollPosition = (element, state) => {"
    "if (!element || !state) return;"
    "const maxScrollTop = Math.max(0, element.scrollHeight - element.clientHeight);"
    "const previousMax = Math.max(0, Number(state.height || 0) - Number(state.clientHeight || 0));"
    "const previousTop = Number(state.top || 0);"
    "const pinnedToBottom = previousMax > 0 && Math.abs(previousTop - previousMax) <= 4;"
    "element.scrollTop = pinnedToBottom ? maxScrollTop : Math.min(maxScrollTop, previousTop);"
    "};"
    "const captureScrollState = () => ({"
    "thread: {"
    "top: talkView.scrollTop,"
    "height: talkView.scrollHeight,"
    "clientHeight: talkView.clientHeight,"
    "},"
    "boxes: Array.from(document.querySelectorAll('[data-scroll-key]')).reduce((acc, element) => {"
