    "acc[key] = captureElementScrollState(element);"
    "return acc;"
    "}, {}),"
    "});"
    "const restoreScrollPosition = (element, state) => {"
    "restoreElementScrollPosition(element, state);"
    "};"
    "const restoreScrollState = (state) => {"
    "if (!state) return;"
    "restoreScrollPosition(talkView, state.thread);"
    "for (const element of document.querySelectorAll('[data-scroll-key]')) {"
    "const key = String(element.dataset.scrollKey || '').trim();"
    "if (!key || !state.boxes[key]) continue;"
    "restoreScrollPosition(element, state.boxes[key]);"
    "}"
    "};"
    "let lastRenderedListSignature = '';"
    "let userIsScrolling = false;"
    "let userScrollTimer = null;"
    "let hasPendingRender = false;"
    "talkView.addEventListener('scroll', () => {"
    "userIsScrolling = true;"
    "clearTimeout(userScrollTimer);"
    "userScrollTimer = setTimeout(() => {"
    "userIsScrolling = false;"
    "if (hasPendingRender) { hasPendingRender = false; renderList(); }"
    "}, 350);"
    "}, { passive: true, capture: true });"
    "const renderList = () => {"
    "const timeline = selectVisibleTimeline(buildRenderableTimeline(filteredEntries()));"
