    "const payload = await response.json().catch(() => ({}));"
    "if (!response.ok || !Array.isArray(payload.messages)) return;"
    "const nextEntries = sortEntriesNewestFirst(payload.messages.slice(-computeEntryFetchLimit()));"
    "const nextEntriesSignature = JSON.stringify(nextEntries);"
