    "};"
    "let _activeEs = null;"
    "let _esReconnectTimer = null;"
    "let _pollLoopTimer = null;"
    "let _sseConnected = false;"
    "let _lastSseAt = 0;"
    "let _realtimeBurstUntil = 0;"
    "const markRealtimeActivity = (durationMs = 10000) => {"
    "const now = Date.now();"
    "_lastSseAt = now;"
    "_realtimeBurstUntil = Math.max(_realtimeBurstUntil, now + durationMs);"
    "};"
    "const sessionAppearsActive = () => {"
    "if (goalManagerRuntimeState === 'running') return true;"
