    "goalManagerRuntimeState = 'running';"
    "} else if (eventType === 'service.goal_audit_completed') {"
    "const event = entry.event || {};"
    "goalManagerRuntimeState = Boolean(event.goal_satisfied) ? 'complete' : 'waiting';"
    "} else if (eventType === 'service.goal_audit_failed' || eventType === 'service.post_turn_followup_failed' || eventType === 'service.goal_manager_compact_failed') {"
    "goalManagerRuntimeState = 'failed';"
    "}"
